var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......읏차!","JPN":"……よいしょ！","ENG":"Gah!","TWN":"……喝啊！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이봐, 다들 살아 있나?","JPN":"おい、みんな生きてるか？","ENG":"Hey! Is everyone alive?","TWN":"喂，大家都還活著嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"이 토미 더 다이하드님이 이딴 걸로 죽을 것 같냐!","JPN":"このトミー・ザ・ダイハード様がこれっぽちで死ぬもんか！","ENG":"Heh! Tommy the Die-hard isn't going down so easily!","TWN":"頑強．湯米會因為這種事情死掉嗎！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"엣퉤퉤! 입에 모래 들어갔어!","JPN":"ペッ！　口に砂が入った！","ENG":"Ptui! Ptui! There's sand in my mouth!","TWN":"啊呸呸！沙子進到嘴巴裡了！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"다리가 깔렸어! 누가 나 좀 꺼내줘!","JPN":"脚が挟まってるんだ！　誰か助けてくれ！","ENG":"My leg's stuck! Someone get me out!","TWN":"腿被壓住了！誰來把我拉出來啊！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"이봐, 존. 내가 그렇게 까탈스러운 여자는 아니라고 생각하는데 말이야......","JPN":"あのね、ジョン。アタシはそこまで気難しい女じゃないと思うけど……","ENG":"Hey, John. I don't consider myself a very picky person,","TWN":"喂，約翰。我覺得我不是個那麼挑剔的女人……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"한 번만 더 이따위 고물에 날 태우려고 했다간 어느날 침대 밑에 수류탄이 굴러다니더라도 날 원망하진 말라고.","JPN":"またこんなオンボロにアタシを乗せようものなら、\\nある日ベッドの下に手榴弾が転がってきても私を恨まないでね。","ENG":"but if you ever try to get me on a piece of junk like this again, you're going to find a grenade rolling around under your bed.","TWN":"但要是你再讓我坐這種老古董，哪天你的床底下滾了顆手榴彈可別怪我。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그건 걱정할 필요 없어.","JPN":"その心配はないさ。","ENG":"You don't have to worry about that.","TWN":"不用擔心。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이번 일이 잘 풀리면 우리가 함께하는 다음 작전 같은 건 없을 테니까.","JPN":"今回のことさえうまくいけば、俺らがともにする作戦なんか二度とないだろうからな。","ENG":"If this goes well, there won't be a next operation that we'll be in together.","TWN":"要是這次的事情順利解決了的話，我們就不會再一起作戰了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......잘 풀리지 않아도 마찬가지겠지만.","JPN":"……まあ、うまくいかなくても同じだろうがな。","ENG":"Then again, there won't be a next operation if we fail.","TWN":"……雖然沒有順利解決也一樣。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그보다 다른 일행들은 어떻게 됐지? 위치 확인 되나?","JPN":"それより他の奴らはどうなった？　位置確認できるか？","ENG":"What happened to all the others? Can you locate them?","TWN":"話說回來，其他人情況怎麼樣了？確認位置了嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"잠깐 기다려 봐.","JPN":"ちょっと待ってな。","ENG":"Hold on.","TWN":"稍等一下。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"......이상한데? 다른 강하선들의 신호가 전혀 안 잡혀.","JPN":"……変だな。他の降下船の信号がまったくつかめない。","ENG":"Hmm... This is odd. There are no signals from other drop ships.","TWN":"……真是奇怪，完全沒有其他降落艙的信號。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L21_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"이거 아무래도 중장거리 전파 통신이 다 먹통인 것 같은데?","JPN":"どうやら、中長距離の電波通信が全部ぶっ壊れてるようだな？","ENG":"It seems the long- and medium-range radio network is all breaking up.","TWN":"中長距離的電波通信好像都不行的樣子耶？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......뉴 오하이오의 스텔스 필드 때문인 것 같군.","JPN":"……ニューオハイオのステルスフィールドのせいだな。","ENG":"It's the stealth field of the New Ohio.","TWN":"……應該是新俄亥俄的隱形場域造成的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"다들 같은 좌표로 다이브 한 거 아냐?","JPN":"みんな同じ座標にダイブしたんじゃないのか？","ENG":"Didn't we all dive to the same coordinates?","TWN":"大家不是躍入到同一個座標嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"왜 근처에 아무도 안 보이는 거지?","JPN":"なぜ近くに誰もいないんだ？","ENG":"How come there's no one around us?","TWN":"為什麼附近看不到任何人？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"항법장치가 낡아서 도착점 오차율이 높았던 모양이야.","JPN":"航法装置が古すぎて、到着地点の誤差率が上がってしまったようだな。","ENG":"Perhaps the old navigation devices on the drop ships malfunctioned.","TWN":"導航設備太老舊了，到達點的誤差率有點高。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"15년도 넘은 물건이니까 무리도 아니지.","JPN":"15年以上の使い古しだし、無理もない。","ENG":"I'm not surprised. They're more than 15 years old.","TWN":"超過15年的東西了，這也沒有辦法。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"그런 거에 우릴 태웠다고?!","JPN":"そんなのに俺らを乗せたのか！？","ENG":"And you made us dive in that old thing?","TWN":"你就讓我們坐這種老古董？！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"아니, 생각해 보면 항법장치 이전에 강하선이 공중분해 될 뻔 했잖아?","JPN":"いや、思い返せば航法装置どうこうの前に、降下船が空中分解するところだったじゃねえか。","ENG":"The navigation device isn't even an issue here. The ship disintegrated into pieces midair!","TWN":"不，在導航設備以先，這個降落艙還差點在空中解體耶？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그럼 뭐 호텔 리무진이라도 타고 올 줄 알았나?","JPN":"なんだよ、リムジンにでも乗るつもりだったのか？","ENG":"What did you expect, a fancy limousine?","TWN":"不然你以為我們會坐豪華專車來嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"살아있으면 된 거지, 용병이잖아?","JPN":"生きてりゃいいだろう、傭兵なんだから。","ENG":"You're alive and that's what matters. You're a mercenary. Act like one.","TWN":"還活著不就行了，我們是傭兵嘛？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"그러고 보니 중간에 떨어져 나간 두 사람은 어떻게 된 거야?","JPN":"そういえば、途中で離れちまった二人はどうなった？","ENG":"Anyway, what happened to the two that got thrown out in the air?","TWN":"話說，中間掉出去的那兩個人怎麼樣了？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"살아있긴 한 거야?","JPN":"生きてはいるのか？","ENG":"Are they even alive?","TWN":"他們還活著嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"걱정 마, 그 두 명 모두 카운터잖아?","JPN":"心配するな、二人ともカウンターだろ？","ENG":"Don't worry. They're both Counters.","TWN":"別擔心，那兩個人不都是制裁者嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"강하선이 쪼개질 때 역추진 로켓을 점화했으니까...... 아마도 죽진 않았을 거다.","JPN":"降下船が壊れたときに逆推進ロケットを点火したから……たぶん死んではいないだろうよ。","ENG":"Besides, I fired the retrorockets when the drop ship broke in two. They should be alive.","TWN":"降落艙斷裂的時候，反推進火箭已經點燃了……所以大概沒死。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그보다 급한 일은 한시바삐 다른 일행들과 합류하는 거다.","JPN":"それより、他の奴らと合流するのが先だ。","ENG":"What's more important is that we join others as soon as possible,","TWN":"比起這個，現在的當務之急，是儘快和其他人會合。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......우리가 온 걸 리플레이서 놈들이 눈치채기 전에.","JPN":"……俺らが来ていることをリプレイサーどもに気づかれる前にな。","ENG":"before the Replacers find out about us.","TWN":"……要趁克隆集團那些傢伙發現我們來到這裡之前。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"뭔가 뾰족한 방법이라도 있어?","JPN":"何か策でもあるの？","ENG":"Any ideas?","TWN":"有什麼有效的辦法嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"전파통신이 막혔으면 레이더도 먹통일 텐데......","JPN":"電波通信がダメなら、レーダーも使えないでしょうし……","ENG":"If all wireless signals are down,","TWN":"通信網斷了的話，雷達應該也用不了……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"네가 자랑하는 이안 주니어의 색적 시스템도 여기선 소용없을 거야.","JPN":"ご自慢のイアン・ジュニアの索敵システムも、ここでは役に立たないと思うわ。","ENG":"the enemy spotting radar on your cherished Ian Jr. will do no good either.","TWN":"你引以為傲的小伊恩索敵系統在這裡也派不上用場。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"방법이야 항상 존재하지, 위험 부담이 좀 있긴 하지만......","JPN":"策ならいつだって用意してるさ、リスクは少しあるけどな。","ENG":"There is always a way. Although what I have in mind might be a tad risky.","TWN":"辦法總是有的，只是會有點風險而已……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"오호?","JPN":"へえ？","ENG":"Oh?","TWN":"喔哦？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"전파통신기 같은 거 없는 옛날에도 다들 전쟁하고 잘 살았어.","JPN":"電波通信機なんてなかった時代でも、戦争してたんだ。","ENG":"People back in the day didn't have a problem fighting wars without radio communication devices.","TWN":"以前沒有電波設備的時候，大家不也能活著走出戰場嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"원시적인 방법이지만...... 무턱대고 돌아다니는 것보단 낫겠지.","JPN":"原始的な方法だが……むやみに出歩くよりかはマシだろう。","ENG":"This is a little bit primitive, but... at least it'd be better than running around with nothing.","TWN":"雖然是很原始的方法……但總比盲目地亂晃好多了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"어이, 토미! 보급품 가방 좀 줘봐!","JPN":"おい、トミー！　補給品のバッグをよこせ！","ENG":"Hey, Tommy! Hand me the supplies carrier!","TWN":"嘿，湯米！補給包給我一下！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"어? 이, 이건 내 건데...... 왜?","JPN":"うん？　こ、これは俺のだが……なぜ？","ENG":"Huh? B-but this is mine... Why do you need it?","TWN":"咦？這、這是我的啊……你要幹嘛？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"필요한 게 있어서 그래.","JPN":"必要なものがあるんだ。","ENG":"I just need something in it.","TWN":"因為我需要一個東西。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뺏어가진 않을 테니까 안심하라고.","JPN":"盗ったりしないから安心しろ。","ENG":"I won't steal the entire thing from you, don't worry.","TWN":"不會搶你的啦，放心。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"킁킁!","JPN":"クンクン！","ENG":"*Sniff, sniff*","TWN":"嗅嗅！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"왜 그래 오르카?","JPN":"どうしたの、オルカ？","ENG":"What is it, Orca?","TWN":"妳這樣是幹嘛啊，奧爾卡？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"냄새가 나......","JPN":"においがする……","ENG":"I smell something...","TWN":"有味道……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"아주 좋은 것의...... 냄새가......","JPN":"とっても良い……においが……","ENG":"Something that's very nice...","TWN":"非常好聞的……味道……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"뭐......?","JPN":"えっ……？","ENG":"What?","TWN":"什麼……？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"어이! 제시카! 이 근처엔 아무것도 안 보여!","JPN":"おい！　ジェシカ！　この辺には何も見当たらないんだが！","ENG":"Hey! Jessica! I don't see anyone around here.","TWN":"喂！潔西卡！這附近什麼都沒有！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"아무래도 엉뚱한 곳에 떨어진 것 같은데...... 오르카는 또 왜 저래?","JPN":"どうやら変なところに落ちたみたいだが……オルカはどうしたんだ？","ENG":"My guess is we ended up in the wrong place... What's going on with Orca?","TWN":"看來我們掉在奇怪的地方了……奧爾卡又是在幹什麼？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"오르카가 냄새를...... 아니, 뭔가를 찾은 것 같아.","JPN":"オルカがにおいを……いや、何かを見つけたみたい。","ENG":"Orca seems to have smelled... I mean, spotted something.","TWN":"奧爾卡在聞味道……不，她好像發現什麼東西的樣子。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"뭐? 난 아무것도 못 봤는데?","JPN":"なんだって？　俺には何も見つからなかったんだが。","ENG":"Huh? I didn't see anything.","TWN":"什麼？我什麼都沒看到啊？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"혹시 적인가?","JPN":"ひょっとして敵か？","ENG":"Could it be enemies?","TWN":"難道是敵人嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"글쎄, 나도 그것까진......","JPN":"さあ、私もまだそこまでは……","ENG":"Well, I can't be sure...","TWN":"這，我也不清楚……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"......저쪽이다!!","JPN":"……あそこ！！","ENG":"There!","TWN":"……在那邊！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L19_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"오, 오르카! 갑자기 달려가면 위험해!","JPN":"オ、オルカ！　急に飛び出したら危険よ！","ENG":"O-Orca, you can't just run away all of a sudden!","TWN":"奧、奧爾卡！亂跑很危險的！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"허어...... 우리 조카들도 그렇지만 역시 어린애들은 활동량이 엄청나구만......","JPN":"やれやれ……親戚の子もそうだけど、子どもってエネルギーが有り余ってるよな……","ENG":"Whew, it's the same for my nephews, but it's amazing how active kids can be.","TWN":"呵呵……我侄子也像那樣，小孩子果然都精力旺盛啊……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"한가한 소리나 하고 있을 때냐? 얼른 따라가!","JPN":"のんびり見てる場合なの？　早くついていきなさいよ！","ENG":"This isn't the time for idle talk! Follow her!","TWN":"現在是閒聊的時候嗎？還不快跟上！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"걱정말라고! 달리기는 자신 있으니까!","JPN":"心配すんな！　足の速さには自信があるからな！","ENG":"Don't worry, I'm second to none when it comes to running.","TWN":"不用擔心啦！我跑步很有自信的！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"......이런 게 정말 효과가 있다고?","JPN":"……こんなので本当に効果があるの？","ENG":"Are you sure this thing will actually work?","TWN":"……這種東西真的有效嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"먹을 거 가지고 장난치면 안 된다고 어릴 적에 엄마한테 안 배웠어?","JPN":"食べ物で遊んじゃいけないって、小さい頃お母さんに言われなかった？","ENG":"Didn't your mom tell you not to play around with food?","TWN":"小時候你媽媽沒告訴你不能玩食物嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"놔! 이거 좀 놔 보라고!","JPN":"やめろ！　勝手なことするなよ！","ENG":"Let go! Let go of me!","TWN":"放手！我叫你放手！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"어이, 진정해!","JPN":"おい、落ち着けよ！","ENG":"Whoa, easy now.","TWN":"欸，你冷靜一點！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"이봐, 메이슨! 잠깐만 보고 돌려준다더니 불을 질러 버리면 어떡해!","JPN":"おい、メイソン！　ちょっと見るだけって言ったじゃないか！　火をつけてどうすんだ！","ENG":"Mason, you son of a gun! You said you just wanted to have a look, then you set it on fire!","TWN":"喂，梅森！你說你看一下就會還我的，現在放火燒掉了是怎樣啊！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"다 큰 어른이 겨우 간식거릴 가지고 뭘 그렇게 흥분하고 그러나?","JPN":"大の大人がおやつなんかで怒んなよ。","ENG":"Come on, you're a grownup. Are you really making big fuss over a snack?","TWN":"都是大人了，不過只是個零食嘛，你在激動什麼？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그리고 태운 건 보급품으로 들어 있던 머시멜로 뿐이잖아?","JPN":"燃やしたって、補給品のマシュマロだけだろ。","ENG":"Besides, it's only the marshmallows in your supplies carrier that I set on fire.","TWN":"而且燒的只是補給品裡的棉花糖啊？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"돌아가면 상자째로 사서 안겨줄 테니까 지금은 좀 참으라고.","JPN":"戻ったら箱ごとで買ってやるから、今は我慢しろよ。","ENG":"I'll buy you boxes of them when we get back. So calm down, Mr. Sweet Tooth.","TWN":"回去我買個幾箱給你，現在先忍忍吧。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"겨우라니! 전투를 하려면 당분 공급이 얼마나 중요한데......!","JPN":"おやつなんかって何だよ！　糖分の補給はすごく大事なんだぞ……！","ENG":"You're kidding! Do you know what low blood sugar does to a combatant in mission?","TWN":"什麼叫只是零食！在戰鬥中補充糖分有多麼重要……！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"나도 딱히 토미 편을 드는 건 아니지만......","JPN":"別にトミーの肩を持つわけじゃないが……","ENG":"Look, I'm not siding with Tommy here,","TWN":"雖然我不是在幫湯米講話……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"봉화로 일행들을 모은다는 건 좀 현실성이 떨어지는 것 같은데......","JPN":"狼煙で味方に連絡するのは、現実味がないと思うがな……","ENG":"but you're creating a beacon, aren't you? I highly doubt that something like that would work...","TWN":"但用烽火來集結其他人似乎不太現實……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"내 말이! 애초에 이건 봉화도 아니고 모닥불이잖아!","JPN":"そうだよ！　そもそもこれは狼煙じゃなくて、焚火に過ぎねえだろ！","ENG":"That's what I'm talking about! And it's hardly a beacon! It barely qualifies as a bonfire!","TWN":"就是啊！而且這也不是烽火，就是個篝火而已嘛！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"거 참 불만이 많군. 나도 다 여러 가지를 고려해서......","JPN":"つべこべ言うな。俺も色んなことを考慮して……","ENG":"Gosh, you're one grumpy fella. I'm doing this for a reason, okay?","TWN":"你們抱怨很多耶。我也是考慮了很多……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"쉿! 다들 조용해 봐!","JPN":"しっ！　みんな、静かにして！","ENG":"Shh! Quiet, everyone!","TWN":"噓！安靜！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"저쪽에서 무슨 소리가 들려.","JPN":"向こうから何か音がする。","ENG":"I hear something from over there.","TWN":"那邊有什麼聲音。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"뭐? 무슨 소리?","JPN":"ん？　何の音だ？","ENG":"Huh? What is it?","TWN":"什麼？什麼聲音？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"어-이! 오르카! 같이 가!","JPN":"お～い！　オルカ！　一緒に行こうぜ！","ENG":"Hey! Orca! Wait for me!","TWN":"喂！奧爾卡！一起走啊！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"슬슬 효과가 나타나는 모양이군.","JPN":"そろそろ効果が出てきたようだな。","ENG":"Ah, so it's working already.","TWN":"看起來逐漸出現效果了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"어, 어떻게? 정말 저 모닥불을 보고 찾아왔다고?","JPN":"な、なぜ？　本当にあの焚火を見てきたのか？","ENG":"B-but how? They couldn't have spotted that small a fire!","TWN":"什、什麼？難道他們真的看到篝火找到這裡了？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"지난번에 보니까 오르카가 머시멜로에 꽤 집착하는 것 같더군.","JPN":"この前、オルカがマシュマロに相当惚れ込んでるように見えてな。","ENG":"I saw the other day Orca was quite obsessed with marshmallows.","TWN":"從上次的事情來看，奧爾卡對棉花糖非常執著。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이런 황량한 곳이라면 설탕 타는 냄새가 꽤 멀리까지 퍼지지.","JPN":"こういう環境だと、砂糖が燃える匂いはかなり遠くまで広がるんだ。","ENG":"And in a barren place like this, the smell of sugar burning flies far and fast.","TWN":"而在這種荒涼的地方，砂糖燒焦的味道會傳得很遠。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"일반인이라면 몰라도 오르카라면 후각에 민감할 테니까 가능성이 클 거라고 생각했다.","JPN":"オルカなら鼻が利きそうだからな、気づいてくれると思ったんだ。","ENG":"If it's none other than Orca, who has an extremely sensitive nose, I thought it would be highly probable.","TWN":"先不說一般人，但奧爾卡的嗅覺很靈敏，所以成功的可能性很大。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"오호, 역시 두뇌파 용병 메이슨!","JPN":"へえ、さすが頭脳派傭兵ね！","ENG":"Way to go, Mason the Intelligent Mercenary!","TWN":"喔哦！不愧是頭腦派傭兵梅森！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"이럴 땐 꽤 베테랑 같아 보여.","JPN":"こういう時は、ベテランに近いものを感じるわ。","ENG":"Really, you could be mistaken for a veteran at times like this.","TWN":"這種時候就很有老手的樣子。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"베테랑 맞거든!","JPN":"いや、ベテランなんだよ！","ENG":"I AM a veteran!","TWN":"本來就是好嘛！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"어이 형씨! 여기에 있었구만! 우리만 낙오된 줄 알았다고.","JPN":"おい、ここにいたのか！　俺たちだけはぐれたかと思ったぜ。","ENG":"Hey, man! You're here! I thought we were the only ones falling behind.","TWN":"喂，老兄！你們原來在這裡！我還以為只有我們脫隊了呢。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그럴 리가, 어쨌든 합류하게 돼서 다행이군.","JPN":"とにかく合流できて良かったな。","ENG":"You don't say. I'm glad you've joined us.","TWN":"怎麼可能只有你們脫隊了，不管怎樣會合了就好。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이제 다음은 경찰 나리들을 찾아 볼 차례......","JPN":"さあ、次は警察組を探す番……","ENG":"Now, it's time to find the police ladies...","TWN":"接下來要找到警察大人們……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"잠깐, 오르카가 왜 날 저렇게 노려보는 거지?","JPN":"待て、なぜオルカがあんなに俺のことを睨んでるんだ？","ENG":"Wait, why is Orca staring at me like that?","TWN":"等等，為什麼奧爾卡要那樣瞪著我啊？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"좋은 것...... 다 타버렸다......","JPN":"マシュマロ……全部焦げた……","ENG":"Nice things... All burnt...","TWN":"好東西……都被燒掉了……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"타버린 건 못 먹는다......","JPN":"焦げたものは食べられない……","ENG":"I can't eat burnt things...","TWN":"燒焦了就沒辦法吃了……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"내 안의 오르카가...... 짜증을 내고 있어......","JPN":"私の中のオルカが……イライラしてる……","ENG":"The Orca inside me is throwing tantrums...","TWN":"在我裡面的奧爾卡……很生氣……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"어이어이, 진정하라고.","JPN":"おいおい、落ち着けよ。","ENG":"Hey, hey. Relax, okay?","TWN":"喂喂，冷靜一點。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"설마 칼이라도 휘두르는 건 아니겠지? 하하.","JPN":"まさか剣とか振り回したりしないよな？　ハハ。","ENG":"You're not going to take a swing at me, are you? Hah hah.","TWN":"妳沒有要對我揮刀吧？哈哈。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"고민 중......","JPN":"考え中……","ENG":"I'm thinking about it...","TWN":"我還在糾結……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......미, 미안하군.","JPN":"……す、すまん。","ENG":"I-I'm sorry.","TWN":"……對、對不起。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"돌아가면 더 맛있는 걸 잔뜩 사줄 테니까 이번엔 좀 봐달라고......","JPN":"戻ったらもっと美味しいものをたくさん奢ってやるから、今回は勘弁してくれよ……","ENG":"Cut me some slack here. I'll buy you lots of nice things when we get back.","TWN":"回去後我給妳買更多更好吃的，這次妳就放過我吧。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"약속...... 기억했다......","JPN":"約束……覚えておく……","ENG":"You promised... I'll remember...","TWN":"約定……我記住了……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"어-이!!","JPN":"おーい！！","ENG":"Hey!","TWN":"喂！！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"제시카! 여기야! 메이슨 일행도 같이 있으니까 얼른 오라고!","JPN":"ジェシカ！　ここだ！　メイソンたちも一緒にいるから早く来いよ！","ENG":"Jessica! Over here! I've found the Mason team here. Come on!","TWN":"潔西卡！這裡！梅森他們也在這裡，快過來！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"총질은 잘해도 발은 느리구만, 하하!","JPN":"銃さばきは素早くても、足は遅いんだな、ハハ！","ENG":"If only you could walk as fast as you can shoot! Hah hah!","TWN":"原來妳槍法狠準但跑不快啊，哈哈！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"그게 문제가 아냐! ......몰려온다!!","JPN":"それどころじゃないよ！　……押し寄せてくる！！","ENG":"That's not the problem! They're coming!","TWN":"那不是問題啊！……敵人來了！！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"뭐?","JPN":"えっ？","ENG":"Huh?","TWN":"什麼？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이런, 다들 전투 준비 해!","JPN":"やれやれ、みんな戦闘に備えろ！","ENG":"Uh-oh. Everyone, prepare for combat!","TWN":"該死，大家做好戰鬥準備！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"전투? 갑자기 무슨 소리야?","JPN":"戦闘？　いきなり何なんだ？","ENG":"Combat? What are you talking about?","TWN":"戰鬥？你突然說些什麼啊？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"말했었지? 이 방법은 위험 부담이 있다고.","JPN":"さっき言ったよな？　この手段はリスクがあるって。","ENG":"I told you, it was a risky move.","TWN":"我說過了吧？這個方法可能會有風險。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"봉화의 문제점은 딱 하나지, 아군 말고 적도 볼 수 있다는 거.","JPN":"狼煙のリスクはたった一つ、味方だけじゃなく、敵にもわかるってことだ。","ENG":"There's a downside to using a beacon: If the ally can see it, the enemy can see it, too.","TWN":"烽火的問題就只有一個，那就是不只有同伴會看到，敵人也會。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"뭐? 서, 설마!!","JPN":"はあ？　ま、まさか！！","ENG":"Huh? N-no way...","TWN":"什麼？該、該不會！！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"......적들이 몰려온다고!! 다들 총 들어!!","JPN":"……敵が押し寄せてくるってば！！　みんな銃を構えて！！","ENG":"We've got enemies coming at us! Grab your guns!","TWN":"……敵人過來了！！都給我拿起槍來！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};